core_pattern.example:
def analysis = askBob(prompt, 'mode-slug')
echo '════════════════════════════════════════════════════════' echo ' Bob — <stage name>' echo '════════════════════════════════════════════════════════' echo analysis echo '════════════════════════════════════════════════════════'
writeFile file: 'bob-<stage>.md', text: analysis archiveArtifacts artifacts: 'bob-<stage>.md', allowEmptyArchive: true

rule.bad:
// Doesn't do what you think
sh "askBob > bob-output.txt"

// askBob() is Groovy — there's no third "outputFile" parameter either
askBob(prompt, 'mode-slug', 'bob-output.txt')  // ignored

output_processing.example:
def analysis = askBob(prompt, 'pipeline-git-diff-overview')
echo analysis

if (analysis.toLowerCase().contains('risk: high')) {
    echo "Bob flagged a high-risk change — marking build UNSTABLE"
    currentBuild.result = 'UNSTABLE'
}

writeFile file: 'bob-pr-review.md', text: analysis
archiveArtifacts artifacts: 'bob-pr-review.md', allowEmptyArchive: true
